})
// 辅助函数：在树形结构中查找节点
function findNodeById(tree, id) {
  for (let node of tree) {
    if (node.stId === id) {
      return node;
    }
    if (node.children) {
      let found = findNodeById(node.children, id);
      if (found) {
        return found;
      }
    }
  }
  return null;
}

